], "correct_index": 0, "explication": ""}, {"question": "Qu'est-ce que le biais d'ancrage ?", "options": ["Comparer avec les concurrents", "S'accrocher à une idée", "Fixer un prix bas", "Le premier chiffre vu sert de référence pour les suivants"], "correct_index": 3, "explication": ""}, {"question": "Un petit oui mène à un grand oui. Quel biais est-ce ?", "options": ["FOMO", "Réciprocité", "Engagement", "Autorité"], "correct_index": 2, "explication": ""}, {"question": "Que signifie le biais de réciprocité ?", "options": ["Être réciproque dans les DMs", "Rendre la pareille quand on reçoit de la valeur", "Suivre ceux qui nous suivent", "Partager le contenu des autres"], "correct_index": 1, "explication": ""}, {"question": "Quelle est la règle éthique fondamentale concernant les biais ?", "options": ["Utiliser tous les biais en même temps", "Toujours délivrer la valeur promise — jamais de fausse urgence", "Ne jamais utiliser de biais cognitifs", "Cacher l'utilisation des biais"], "correct_index": 1, "explication": ""}, {"question": "Comment appliquer l'urgence sur Instagram ?", "options": ["Publier à heures fixes", "Publier tous les jours", "Utiliser des couleurs vives", "Stories avec compte à rebours, offres limitées, places restreintes"], "correct_index": 3, "explication": ""}, {"question": "Qu'est-ce qui vaut 100 arguments selon la formation ?", "options": ["Un résultat client", "Un bon hook", "Un prix bas", "Un beau visuel"], "correct_index": 0, "explication": ""}, {"question": "Comment créer de la rareté de manière éthique ?", "options": ["Ne publier qu'une fois par mois", "Dire « dernières places » même si c'est faux", "Fermer son compte régulièrement", "Limiter réellement l'accès et délivrer la valeur promise"], "correct_index": 3, "explication": ""}, {"question": "Pourquoi nos ancêtres économisaient-ils leur énergie ?", "options": ["Pour survivre en cas de pénurie", "Pour courir plus vite", "Pour réfléchir mieux", "Pour dormir plus longtemps"], "correct_index":