, "correct_index": 0, "explication": ""}, {"question": "Combien coûte la certification Instagram (coche bleue) ?", "options": ["9,99€/mois", "29,99€/mois", "16,99€/mois", "Gratuit"], "correct_index": 2, "explication": ""}, {"question": "Quelle catégorie de compte est recommandée ?", "options": ["Entreprise", "Personnel", "Entrepreneuriat (puis Créateur)", "Public"], "correct_index": 2, "explication": ""}, {"question": "Pourquoi la catégorie Entrepreneuriat est-elle recommandée ?", "options": ["Pour avoir plus d'abonnés", "Pour apparaître en premier", "Pour être vérifié", "Pour avoir accès à toutes les musiques"], "correct_index": 3, "explication": ""}, {"question": "Quelle règle s'applique à la photo de profil sur plusieurs réseaux ?", "options": ["Changer de PDP pour chaque réseau", "Même PDP partout pour être reconnaissable", "Utiliser un logo uniquement", "Alterner entre photo et logo"], "correct_index": 1, "explication": ""}, {"question": "Le nom de profil (différent du @) sert à :", "options": ["Le SEO Instagram et la certification", "L'esthétique uniquement", "Rien de spécial", "Remplacer la bio"], "correct_index": 0, "explication": ""}, {"question": "Que mettre dans le nom de profil pour le SEO ?", "options": ["Uniquement des émojis", "Le nom de son entreprise uniquement", "Son pseudo", "Prénom + Nom + mots-clés nichés"], "correct_index": 3, "explication": ""}, {"question": "Le lien en bio doit rediriger vers :", "options": ["Votre contenu gratuit, Calendly ou page de contact", "Votre page Facebook", "Votre profil LinkedIn", "Votre email"], "correct_index": 0, "explication": ""}, {"question": "Dans le scénario Yasmine, en combien de semaines a-t-elle atteint 500 abonnés ?", "options": ["2 semaines", "12 semaines", "8 semaines", "4 semaines"], "correct_index": 3, "explication": ""}, {"question": "Quel taux de conversion Yasmine a-t-elle atteint ?", "options": ["8%", "15%", "50%", "23%"], "correct_index": 3, "explication": ""}, {"question": "Qu'est-ce qui a fait la plus grande différence selon le bilan de Yasmine ?", "options": ["La publicité payante", "Le nombre de réels publiés", "Un profil clair compris en 3 secondes + stories à la une", "Les collaborations"], "correct_index": 2, "explication": ""}, {"question": "Calendly sert à :", "options": ["Créer des réels", "Programmer des publications", "Gérer les hashtags", "Automatiser la prise de RDV 24h/24"], "correct_index": 3, "explication": ""}, {"question": "La certification augmente :", "options": ["La valeur perçue, la crédibilité et l'autorité", "Le nombre de likes", "Le nombre de réels publiables", "La portée de chaque publication"], "correct_index": 0, "explication": ""}, {"question": "Pourquoi la photo doit-elle montrer un visage humain ?", "options": ["C'est obligatoire", "Les profils avec visage reçoivent 38% plus de clics que les logos", "Instagram favorise les visages", "C'est plus joli"], "correct_index": 1, "explication": ""}, {"question": "Que faut-il vérifier avant de créer du contenu ?", "options": ["Avoir 1000 abonnés minimum", "Acheter des followers", "Optimiser son profil d'abord — c'est la vitrine", "Avoir un site web"], "correct_index": 2, "explication": ""}, {"question": "La story à la une « FAQ » sert à :", "options": ["Répondre aux questions et éliminer les objections avant le premier DM", "Montrer sa vie personnelle", "Publier ses tarifs", "Partager des memes"], "correct_index": 0, "explication": ""}, {"question": "Qu'est-ce qu'un « @ optimisé » ?", "options": ["Un @ avec beaucoup de chiffres", "Un @ en majuscules", "Un @ simple, mémorisable et recherchable", "Un @ identique à son nom"], "correct_index": 2, "explication": ""}, {"question": "Le compte pro débloque :", "options": ["Plus de followers", "La certification gratuite", "L'accès aux statistiques et toutes les fonctionnalités", "Les messages sponsorisés"], "correct_index": 2, "explication": ""}, {"question": "Combien de DMs Yasmine a-t-elle reçus en 4 semaines ?", "options": ["10", "100", "30", "500"], "correct_index": 2, "explication": ""}, {"question": "Un profil non optimisé est comparé à :", "options": ["Un mauvais contenu", "Une porte fermée — le visiteur ne comprend pas et repart", "Un compte privé", "Un compte sans abonnés"], "correct_index": 1, "explication": ""}, {"question": "Quelle plateforme faut-il maîtriser avant d'en ouvrir une deuxième ?", "options": ["Toutes en même temps", "La première choisie — être partout = être nulle part", "Facebook obligatoirement", "TikTok d'abord"], "correct_index": 1, "explication": ""}, {"question": "L'algorithme LinkedIn favorise :", "options": ["Les Réels", "L'engagement dans les 60 premières minutes", "Le watchtime", "Les hashtags"], "correct_index": 1, "explication": ""}, {"question": "La story à la une « Méthode » sert à :", "options": ["Expliquer son approche en 3-5 étapes claires pour que le prospect visualise la transformation", "Montrer ses diplômes", "Publier des citations", "Partager des tutoriels techniques"], "correct_index": 0, "explication": ""}], "chapitre_id": "8e7a8833-6379-489c-ba97-fbc77c8b030e"}$quiz$::jsonb);
