SELECT public.import_quiz_from_json($quiz${"titre": "Quiz Marketing Digital — Module 6 — Réels : Algorithme & Viralité", "description": "30 questions. Valide ce quiz pour débloquer la suite de la formation.", "max_errors": 3, "status": "published", "questions": [{"question": "Quel est le signal n°1 pour l'algorithme Instagram ?", "options": ["Les likes", "Les commentaires", "Le Watchtime (temps de visionnage)", "Les partages"], "correct_index": 2, "explication": ""}, {"question": "Quelle est la hiérarchie correcte des signaux sociaux ?", "options": ["Likes > Vues > Commentaires > Partages", "Abonnements > Likes > Commentaires > Vues", "Watchtime > Partages > Commentaires > Enregistrements > Abonnements > Likes", "Commentaires > Likes > Partages > Watchtime"], "correct_index": 2, "explication": ""}, {"question": "Combien de hashtags maximum sont recommandés ?", "options": ["3", "20", "3 à 10", "30"], "correct_index": 2, "explication": ""}, {"question": "Quelle est la meilleure tranche horaire pour publier ?", "options": ["6h-8h", "18h-21h", "10h-12h", "22h-00h"], "correct_index": 1, "explication": ""}, {"question": "Où activer la qualité HD sur Instagram ?", "options": ["En filmant", "Dans les filtres", "Paramètres → Compte → Qualité média → Haute qualité", "Au moment de la publication"], "correct_index": 2, "explication": ""}, {"question": "Que doit contenir la 1ère ligne de la description ?", "options": ["Un hashtag", "Votre nom", "Le CTA — c'est la seule ligne visible avant « ...plus »", "Un émoji"], "correct_index": 2, "explication": ""}, {"question": "100K vues avec 2 secondes de watchtime est :", "options": ["Un mauvais signal pour l'algorithme", "Un excellent résultat", "Impossible", "Normal"], "correct_index": 0, "explication": ""}, {"question": "Comment fonctionne la diffusion d'un réel ?", "options": ["Publication → échantillon → analyse des signaux → push ou stop", "Il est montré à tous vos abonnés d'un coup", "Il est envoyé par email", "Il faut payer pour