, "explication": ""}, {"question": "La moyenne d'enregistrement sur Instagram est de :", "options": ["0,5 à 1%", "2 à 5%", "10 à 15%", "20%+"], "correct_index": 1, "explication": ""}, {"question": "Combien d'abonnés Sarah avait-elle après 3 mois ?", "options": ["2 000", "5 000", "50 000", "15 200"], "correct_index": 3, "explication": ""}, {"question": "Le mix de hashtags recommandé est :", "options": ["10 larges uniquement", "3 larges + 3 moyens + 3 spécifiques", "30 hashtags populaires", "Aucun hashtag"], "correct_index": 1, "explication": ""}, {"question": "Que faut-il éviter comme hashtags ?", "options": ["Les hashtags de niche", "Les hashtags en français", "#love #instagood #follow — trop génériques et inutiles", "Les hashtags avec des chiffres"], "correct_index": 2, "explication": ""}, {"question": "L'objectif final avant chaque publication est de se demander :", "options": ["Est-ce que c'est joli ?", "Ce contenu donne-t-il envie à un inconnu de s'abonner OU de m'envoyer un DM ?", "Est-ce que j'ai assez de hashtags ?", "Est-ce que la musique est tendance ?"], "correct_index": 1, "explication": ""}, {"question": "Où trouver les heures actives de votre audience ?", "options": ["Sur Google", "C'est la même pour tout le monde", "En demandant en story", "Insights → Audience → Heures actives"], "correct_index": 3, "explication": ""}, {"question": "Un abonné est un signal important parce que :", "options": ["Il augmente votre vanity metrics", "Il améliore votre SEO", "Il peut acheter des produits", "Il garantit du watchtime futur sur vos prochains contenus"], "correct_index": 3, "explication": ""}, {"question": "Créer une série (Partie 1, 2, 3...) favorise quel signal ?", "options": ["Les abonnements", "Les partages", "Les likes", "Les vues"], "correct_index": 0, "explication": ""}, {"question": "Le like est le signal le moins puissant car :", "options": ["Instagram ne le compte plus", "Il diminue la portée", "Il n'est pas visible", "Il demande peu d'effort à l'utilisateur"], "correct_index": 3, "explication": ""}, {"question": "« Ne cherchez pas les vues à tout prix » — pourquoi ?", "options": ["Les vues coûtent cher", "Les vues sont fausses", "L'algo regarde la qualité (rétention), pas la quantité", "Trop de vues = pénalité"], "correct_index": 2, "explication": ""}, {"question": "Sur quels signaux faut-il se concentrer en priorité ?", "options": ["Le top 4 : Watchtime, Partages, Commentaires, Enregistrements", "Likes et vues", "Uniquement les abonnements", "Tous de manière égale"], "correct_index": 0, "explication": ""}, {"question": "Sarah a ajouté quel CTA systématiquement au mois 2 ?", "options": ["Likez si d'accord", "Partagez", "Abonnez-vous", "Enregistrez pour ne pas oublier"], "correct_index": 3, "explication": ""}, {"question": "Combien de clientes coaching Sarah a-t-elle signées en 3 mois ?", "options": ["5", "12", "22", "50"], "correct_index": 2, "explication": ""}], "chapitre_id": "48f776ca-834b-4d46-a259-9bbd487705d1"}$quiz$::jsonb);
SELECT public.import_quiz_from_json($quiz${"titre": "Quiz Marketing Digital — Module 7 — Stories & Routines de croissance", "description": "30 questions. Valide ce quiz pour débloquer la suite de la formation.", "max_errors": 3, "status": "published", "questions": [{"question": "Combien d'utilisateurs regardent les Stories chaque jour dans le monde ?", "options": ["100M+", "300M+", "500M+", "1 milliard+"], "correct_index": 2, "explication": ""}, {"question": "Quel pourcentage d'utilisateurs regarde les Stories avant le feed ?", "options": ["50%", "65%", "86%", "75%"], "correct_index": 2, "explication": ""}, {"question": "Quels sont les 5 types de stories à maîtriser ?", "options": ["Valeur, Coulisses, Engagement, Preuve sociale, Vente/CTA", "Pub, promo, offre, prix, lien", "Matin, midi, après-midi, soir, nuit", "Photo, vidéo, texte, sondage, quiz"], "correct_index": 0, "explication": ""}, {"question": "Quel est le ratio valeur/vente pour les stories ?", "options": ["80/20", "60/40", "50/50", "100/0"], "correct_index": 0, "explication": ""}, {"question": "Combien de stories par jour sont recommandées ?", "options": ["1-2", "3-7", "10-20", "30+"], "correct_index": 1, "explication": ""}, {"question": "La séquence de stories qui convertit suit quelle structure ?", "options": ["Offre → Prix → CTA", "Photo → Texte → Sondage", "Question → Réponse → Lien", "Accroche → Problème → Valeur → Preuve → CTA"], "correct_index": 3, "explication": ""}, {"question": "Quel sticker est le plus efficace pour collecter les objections ?", "options": ["Sondage", "Question ouverte", "Quiz", "Curseur"], "correct_index": 1, "explication": ""}, {"question": "Le sticker « Compte à rebours » sert à :", "options": ["Créer de l'anticipation pour un live, un lancement, un événement", "Montrer l'heure", "Compter ses abonnés", "Timer ses stories"], "correct_index": 0, "explication": ""}, {"question": "Quel jour est recommandé pour les stories « Preuve sociale » ?", "options": ["Lundi", "Vendredi", "Mercredi", "Dimanche"], "correct_index": 1, "explication": ""}, {"question": "Quel jour est recommandé pour la « Vente douce » ?", "options": ["Lundi", "Mercredi", "Samedi", "Dimanche"], "correct_index": 2, "explication": ""}, {"question": "Combien de comptes « leaders » faut-il identifier pour les routines ?", "options": ["3-5", "Le plus possible", "50-100", "10-30"], "correct_index": 3, "explication": ""}, {"question": "Quelle est la limite d'interactions par heure ?", "options": ["5-10", "15-30", "50-100", "Illimité"], "correct_index": 1, "explication": ""}, {"question": "Quel type d'interaction a le plus fort impact ?", "options": ["Le follow", "Le like", "Le commentaire de valeur", "Le partage"], "correct_index": 2, "explication": ""}, {"question": "Un « commentaire de valeur » c'est :", "options": ["Un emoji 👏", "« Top ! »", "« Intéressant »", "Validation + apport personnel (expérience, ressource, angle)"], "correct_index": 3, "explication": ""}, {"question": "Parmi les abonnés d'un compte leader, qui cibler en priorité ?", "options": ["Les abonnés les plus récents", "Uniquement les comptes vérifiés", "Tous les abonnés", "Les commentateurs (les plus qualifiés et engagés)"], "correct_index": 3, "explication": ""}, {"question": "Éduquer l'algorithme consiste à :", "options": ["Liker et sauvegarder du contenu de votre niche chaque jour", "Acheter des publicités", "Publier 10 réels par jour", "Envoyer des DMs à Instagram"], "correct_index": 0, "explication": ""}, {"question": "Combien de temps dure la routine quotidienne recommandée ?", "options": ["30-45 minutes", "10 minutes", "2 heures", "4 heures"], "correct_index": 0, "explication": ""}, {"question": "Les réponses aux stories augmentent le reach de :", "options": ["+10%", "+40%", "+25%", "+80%"], "correct_index": 1, "explication": ""}, {"question": "Le setting sur chaque viewer consiste à :", "options": ["Bloquer les inactifs", "Envoyer un message personnalisé à chaque personne qui regarde vos stories", "Analyser les statistiques", "Changer les paramètres du compte"], "correct_index": 1, "explication": ""}, {"question": "Dans le cas Mehdi (coach sportif), quelle était sa stratégie en 3 mots ?", "options": ["Stories + Setting + Routines", "Réels + Pub + Site", "Contenu + Hashtags + Boost", "Followers + Likes + Vues"], "correct_index": 0, "explication": ""}, {"question": "Combien de leads/mois Mehdi générait-il au mois 3 ?", "options": ["10", "25", "100", "52"], "correct_index": 3, "explication": ""}, {"question": "Le mix stories de Mehdi était :", "options": ["5 stories de vente", "3 valeur + 2 offre", "2 perso + 2 valeur + 1 CTA", "1 story par jour"], "correct_index": 2, "explication": ""}, {"question": "Quand arrêter les routines de croissance ?", "options": ["Jamais", "Quand l'organique via Réels prend le relais", "Après 1 semaine", "Quand on atteint 10K abonnés"], "correct_index": 1, "explication": ""}, {"question": "Les stories à la une « Transformations » de Mehdi montrent :", "options": ["Ses diplômes", "Ses tarifs", "Des avant/après de ses clients — preuve sociale", "Son emploi du temps"], "correct_index": 2, "explication": ""}, {"question": "Le CA de Mehdi au mois 3 était de :", "options": ["3 200€/mois", "2 000€", "1 000€", "5 000€"], "correct_index": 0, "explication": ""}, {"question": "Combien de commentaires/jour Mehdi faisait-il pendant les routines ?", "options": ["5", "50", "15-20", "100"], "correct_index": 2, "explication": ""}, {"question": "Le setting est décrit comme :", "options": ["De la prospection froide", "De la pub déguisée", "Du spam massif", "Engager une conversation naturelle en DM à partir d'une story"], "correct_index": 3, "explication": ""}, {"question": "Une erreur fatale en stories est :", "options": ["Poster 5 stories par jour", "Utiliser des sondages", "Poster sans régularité (1 story par semaine)", "Montrer sa vie personnelle"], "correct_index": 2, "explication": ""}, {"question": "Le contenu « trop parfait » en stories est :", "options": ["Une erreur — montrez l'imparfait, le vrai, le quotidien", "Recommandé", "Obligatoire pour les pros", "Meilleur pour l'algorithme"], "correct_index": 0, "explication": ""}, {"question": "Répondre à CHAQUE message reçu en story est :", "options": ["Impossible", "Optionnel", "Seulement pour les gros comptes", "Obligatoire — chaque réponse = conversation = confiance"], "correct_index": 3, "explication": ""}], "chapitre_id": "6161f616-4678-4bb1-bd3a-200374211d8e"}$quiz$::jsonb);
SELECT public.import_quiz_from_json($quiz${"titre": "Quiz Marketing Digital — Module 8 — Boost Instagram : Amplifier vos Réels", "description": "30 questions. Valide ce quiz pour débloquer la suite de la formation.", "max_errors": 3, "status": "published", "questions": [{"question": "Quels sont les 5 niveaux de conscience de Schwartz ?", "options": ["Intéressé, Engagé, Convaincu, Acheteur, Fidèle", "Ignorant, Curieux, Informé, Décidé, Satisfait", "Inconscient, Conscient du problème, Conscient de la solution, Conscient du produit, Le plus conscient", "Prospect, Lead, Opportunity, Client, Ambassadeur"], "correct_index": 2, "explication": ""}, {"question": "Quel contenu pour un prospect « Inconscient » ?", "options": ["Storytelling, avant/après — éveiller la prise de conscience", "Offre directe + urgence", "Témoignages clients", "Prix barré + promotion"], "correct_index": 0, "explication": ""}, {"question": "Quel contenu pour « Le plus conscient » ?", "options": ["Offre directe + urgence + CTA clair", "Storytelling émotionnel", "Contenu éducatif", "FAQ et tutoriels"], "correct_index": 0, "explication": ""}, {"question": "Pourquoi faut-il booster depuis la version web ?", "options": ["Meilleure qualité vidéo", "Instagram l'exige", "Plus de fonctionnalités", "La version mobile coûte le DOUBLE à cause des frais App Store"], "correct_index": 3, "explication": ""}, {"question": "Quel objectif de boost est recommandé ?", "options": ["Plus de vues", "Vous écrire (DMs)", "Plus de likes", "Visiter le profil"], "correct_index": 1, "explication": ""}, {"question": "Quel budget quotidien est recommandé pour commencer ?", "options": ["1€/jour", "20€/jour", "5€/jour", "50€/jour"], "correct_index": 2, "explication": ""}, {"question": "Combien de temps attendre avant de juger un boost ?", "options": ["48 heures", "24 heures", "12 heures", "1 semaine"], "correct_index": 0, "explication": ""}, {"question": "Un réel qui a floppé en organique doit-il être boosté ?", "options": ["Oui, le boost le sauvera", "Non — le boost amplifie, il ne sauve pas un mauvais contenu", "Oui, mais avec un gros budget", "Seulement s'il a un bon hook"], "correct_index": 1, "explication": ""}, {"question": "Un bon taux de DMs pour 10€ de boost est :", "options": ["> 5 DMs", "> 1 DM", "> 10 DMs", "> 50 DMs"], "correct_index": 1, "explication": ""}, {"question": "Un bon taux de nouveaux abonnés pour 10€ est :", "options": ["> 1 abonné", "> 100 abonnés", "> 20 abonnés", "> 5 abonnés"], "correct_index": 3, "explication": ""}, {"question": "Le ciblage recommandé pour un premier boost est :", "options": ["Automatique — laissez l'algorithme travailler", "Ciblage par centres d'intérêt", "Ciblage manuel très précis", "Ciblage par pays uniquement"], "correct_index": 0, "explication": ""}, {"question": "Quand augmenter le budget du boost ?", "options": ["Quand vous recevez des DMs qualifiés et que le coût par DM est stable", "Dès le 1er jour", "Après 1 mois", "Jamais, restez à 5€"], "correct_index": 0, "explication": ""}, {"question": "Comment augmenter le budget ?", "options": ["Par paliers : 5€ → 10€ → 15€/jour", "×3 d'un coup", "Directement à 50€/jour", "Alterner 5€ et 20€"], "correct_index": 0, "explication": ""}, {"question": "Quand arrêter un boost ?", "options": ["Après 24h", "Jamais", "Quand on a 100 vues", "Aucun DM après 48h et 15-20€ dépensés"], "correct_index": 3, "explication": ""}, {"question": "Un réel boosté de plus de 7 jours est considéré comme :", "options": ["Parfait", "Optimal", "« Mort » par l'algorithme", "Meilleur qu'un réel récent"], "correct_index": 2, "explication": ""}, {"question": "Le prérequis n°1 avant de booster est :", "options": ["Profil et contenu optimisés en amont", "Avoir 10K abonnés", "Avoir un site web", "Avoir fait de la pub Facebook"], "correct_index": 0, "explication": ""}, {"question": "Quelle page doit être associée au compte Instagram ?", "options": ["Une page LinkedIn", "Un compte Twitter", "Une page Facebook", "Un blog WordPress"], "correct_index": 2, "explication": ""}, {"question": "Nadia (coach bien-être) a investi combien en boost ?", "options": ["20€", "100€", "50€", "500€"], "correct_index": 2, "explication": ""}, {"question": "Combien de DMs Nadia a-t-elle reçus grâce au boost ?", "options": ["3", "12", "50", "100"], "correct_index": 1, "explication": ""}, {"question": "Quel ROI Nadia a-t-elle obtenu (CA / investissement) ?", "options": ["×5", "×24", "×10", "×50"], "correct_index": 1, "explication": ""}, {"question": "Un prospect « Conscient du problème » nécessite quel type de hook ?", "options": ["Offre limitée", "Témoignage client", "« Vous galèrez avec [X] ? » — nommer sa douleur", "Prix barré"], "correct_index": 2, "explication": ""}, {"question": "Un prospect « Conscient de la solution » compare :", "options": ["Les prix uniquement", "Les différentes options et approches", "Les avis Google", "Les publicités"], "correct_index": 1, "explication": ""}, {"question": "Un prospect « Conscient du produit » a besoin de :", "options": ["Éducation générale", "Bénéfices concrets + garantie + témoignages + réponse aux objections", "Contenu divertissant", "Plus de followers"], "correct_index": 1, "explication": ""}, {"question": "Le rechargement automatique du budget doit-il être activé au début ?", "options": ["Oui, toujours", "Peu importe", "Oui, pour ne pas interrompre le boost", "Non — décidez manuellement selon les résultats"], "correct_index": 3, "explication": ""}, {"question": "Combien de meilleurs réels du mois faut-il booster ?", "options": ["Tous", "1 seul", "10+", "2-3"], "correct_index": 3, "explication": ""}, {"question": "Un boost sans CTA dans le réel génère :", "options": ["Des clients", "Des abonnés qualifiés", "Des vues payées sans conversion", "Des DMs automatiques"], "correct_index": 2, "explication": ""}, {"question": "La portée d'un boost est bonne si elle est :", "options": ["×1 votre portée organique", "Peu importe la portée", "×100 votre portée organique", "×3 à ×10 votre portée organique"], "correct_index": 3, "explication": ""}, {"question": "Les visites profil après boost sont bonnes si :", "options": ["> 1% de la portée", "> 50% de la portée", "> 20% de la portée", "> 5% de la portée"], "correct_index": 3, "explication": ""}, {"question": "Le tunnel du boost est :", "options": ["Pub → Site → Achat", "Boost → Followers → Vente", "Réel boosté → Profil → Stories à la une → DM → Appel → Client", "Pub → Email → Vente"], "correct_index": 2, "explication": ""}, {"question": "Quelle catégorie choisir lors du passage en compte pro ?", "options": ["Entrepreneuriat", "Personnel", "Entreprise", "Blog personnel"], "correct_index": 0, "explication": ""}], "chapitre_id": "70f05d3f-9bcf-4587-b4c9-dbf80bca3e9b"}$quiz$::jsonb);
SELECT public.import_quiz_from_json($quiz${"titre": "Quiz Marketing Digital — Module 9 — Le Parcours Client", "description": "30 questions. Valide ce quiz pour débloquer la suite de la formation.", "max_errors": 3, "status": "published", "questions": [{"question": "Quelles sont les 5 étapes du parcours client ?", "options": ["Voir, Cliquer, Acheter, Payer, Revenir", "Publier, Liker, Commenter, Partager, Vendre", "Attirer, Connecter, Engager, Convertir, Fidéliser", "Créer, Diffuser, Analyser, Optimiser, Monétiser"], "correct_index": 2, "explication": ""}, {"question": "L'étape « Attirer » utilise quels outils ?", "options": ["Réels + Boost + Routines de croissance + Hashtags", "Publicité Google", "Email marketing", "Affiliation"], "correct_index": 0, "explication": ""}, {"question": "L'étape « Connecter » repose sur :", "options": ["La pub payante", "Le profil optimisé + stories quotidiennes + stories à la une", "Le cold emailing", "Les webinaires"], "correct_index": 1, "explication": ""}, {"question": "L'étape « Engager » transforme la relation de :", "options": ["Froide à tiède", "Gratuite à payante", "Passive (il regarde) à active (il vous écrit en DM)", "Locale à internationale"], "correct_index": 2, "explication": ""}, {"question": "Quel est l'outil principal de l'étape « Engager » ?", "options": ["Le setting en DM", "Les Réels", "La certification", "Les hashtags"], "correct_index": 0, "explication": ""}, {"question": "L'étape « Convertir » consiste à :", "options": ["Créer du contenu", "Augmenter les vues", "Gagner des abonnés", "Transformer un prospect intéressé en client payant"], "correct_index": 3, "explication": ""}, {"question": "Quels outils servent à convertir ?", "options": ["Réels et hashtags", "Boost et publicités", "Stories et routines", "Closing DM + Appel découverte + Preuves sociales"], "correct_index": 3, "explication": ""}, {"question": "Si les étapes 1-2-3 sont bien faites, le prospect arrive en appel convaincu à :", "options": ["20%", "80%", "50%", "100%"], "correct_index": 1, "explication": ""}, {"question": "L'étape « Fidéliser » sert à :", "options": ["Vendre plus cher", "Garder le client, le faire revenir et le faire recommander", "Augmenter les abonnés", "Réduire les coûts"], "correct_index": 1, "explication": ""}, {"question": "Un client satisfait est décrit comme :", "options": ["Un coût supplémentaire", "Un cas unique", "Quelqu'un à ignorer", "Votre meilleure publicité — la boucle se referme"], "correct_index": 3, "explication": ""}, {"question": "Erreur fatale n°1 : sauter des étapes signifie :", "options": ["Essayer de vendre à quelqu'un qui ne vous connaît pas encore", "Publier trop souvent", "Ne pas utiliser de hashtags", "Changer de niche"], "correct_index": 0, "explication": ""}, {"question": "En combien de temps maximum faut-il répondre à un DM ?", "options": ["24 heures", "6 heures", "2 heures", "48 heures"], "correct_index": 2, "explication": ""}, {"question": "Vendre trop tôt dans la conversation signifie :", "options": ["Proposer une offre au 3ème message", "Envoyer son prix dès le premier message sans qualifier", "Faire un appel découverte", "Demander le budget"], "correct_index": 1, "explication": ""}, {"question": "Sans conversation (DM), pas de :", "options": ["Abonnés", "Likes", "Contenu", "Vente"], "correct_index": 3, "explication": ""}, {"question": "Chaque témoignage de client satisfait nourrit quelle étape ?", "options": ["Engager", "Attirer (la boucle recommence)", "Convertir", "Aucune"], "correct_index": 1, "explication": ""}, {"question": "Le contenu gratuit dans l'étape « Engager » sert à :", "options": ["Remplacer l'offre payante", "Remplir le feed", "Divertir l'audience", "Capturer le contact en DM"], "correct_index": 3, "explication": ""}, {"question": "Que se passe-t-il si vous vendez trop tôt dans le parcours client ?", "options": ["Le prospect achète plus vite", "L'algorithme vous pénalise", "Le prospect n'est pas prêt et vous perdez la vente", "Rien, c'est la bonne approche"], "correct_index": 2, "explication": ""}, {"question": "La correction de l'erreur « pas de CTA » est :", "options": ["Chaque contenu doit avoir UN objectif clair : s'abonner, DM, enregistrer", "Publier plus souvent", "Utiliser des hashtags", "Acheter des abonnés"], "correct_index": 0, "explication": ""}, {"question": "Yasmine (coach confiance) a signé combien de clientes en 2 mois ?", "options": ["2", "4", "6", "10"], "correct_index": 2, "explication": ""}, {"question": "Combien Yasmine a-t-elle investi en boost ?", "options": ["35€", "0€", "100€", "500€"], "correct_index": 0, "explication": ""}, {"question": "Le CA total de Yasmine en 2 mois était de :", "options": ["1 200€", "2 400€", "3 600€", "6 000€"], "correct_index": 2, "explication": ""}, {"question": "Le CTA de Yasmine dans ses réels était :", "options": ["Likez et partagez", "Abonnez-vous", "Écris-moi CONFIANCE en DM", "Visitez mon site"], "correct_index": 2, "explication": ""}, {"question": "Les clientes supplémentaires de Yasmine sont venues par :", "options": ["La pub Instagram", "Le bouche-à-oreille — ses clientes la recommandent", "LinkedIn", "Google"], "correct_index": 1, "explication": ""}, {"question": "Le parcours de Yasmine prouve que :", "options": ["Il faut un gros budget", "Il faut au moins 10K abonnés", "Il faut être expert en vidéo", "Les 5 étapes appliquées, même simplement, génèrent des résultats"], "correct_index": 3, "explication": ""}, {"question": "L'appel découverte de Yasmine durait :", "options": ["5 min", "1 heure", "20 min", "2 heures"], "correct_index": 2, "explication": ""}, {"question": "Répondre lentement aux DMs est un problème car :", "options": ["C'est impoli", "Les DMs expirent après 24h", "Instagram pénalise les réponses lentes", "Un prospect chaud ne reste pas chaud longtemps — il passe à autre chose"], "correct_index": 3, "explication": ""}, {"question": "Le suivi DM pour fidéliser consiste en :", "options": ["Envoyer des promotions quotidiennes", "1-3 DMs/semaine de valeur pour rester dans l'esprit de l'audience", "Relancer les prospects non intéressés", "Envoyer des memes"], "correct_index": 1, "explication": ""}, {"question": "Demander des témoignages sert à :", "options": ["Nourrir l'étape Attirer — chaque témoignage = preuve sociale pour les prochains prospects", "Remplir les stories", "Faire plaisir aux clients", "Augmenter les likes"], "correct_index": 0, "explication": ""}, {"question": "La séquence correcte avant de proposer une offre en DM est :", "options": ["Qualifier (comprendre le besoin) → Appel découverte → Proposition", "Prix → Offre → CTA", "Offre → Relance → Relance → Abandon", "Salutation → Prix → Lien de paiement"], "correct_index": 0, "explication": ""}, {"question": "Le contenu gratuit de Yasmine était :", "options": ["Guide : 5 exercices pour reprendre confiance en soi", "Un ebook de 200 pages", "Un coaching gratuit d'1 heure", "Un audit complet gratuit"], "correct_index": 0, "explication": ""}], "chapitre_id": "e54a59e9-18f0-45eb-b65e-5d5a601b320f"}$quiz$::jsonb);
SELECT public.import_quiz_from_json($quiz${"titre": "Quiz Marketing Digital — Module 10 — Analytics, IA & Stratégie long terme", "description": "30 questions. Valide ce quiz pour débloquer la suite de la formation.", "max_errors": 3, "status": "published", "questions": [{"question": "Quelles stats faut-il lire chaque semaine ?", "options": ["Likes et followers", "Portée, interactions, visites profil, taux d'enregistrement, clics lien bio", "Uniquement les vues", "Le nombre de publications"], "correct_index": 1, "explication": ""}, {"question": "Quel outil IA est recommandé dans la formation ?", "options": ["ChatGPT", "Claude (claude.ai)", "Midjourney", "Copilot"], "correct_index": 1, "explication": ""}, {"question": "La fonctionnalité « Projets » de Claude sert à :", "options": ["Créer des images", "Programmer des publications", "Centraliser votre contexte de niche pour ne plus le répéter", "Analyser vos statistiques"], "correct_index": 2, "explication": ""}, {"question": "L'IA doit être utilisée pour :", "options": ["Remplacer votre voix et personnalité", "Copier-coller tel quel sans relire", "Aller plus vite — structurer, rédiger, trouver des idées", "Créer du contenu automatiquement sans intervention"], "correct_index": 2, "explication": ""}, {"question": "La règle de l'IA est :", "options": ["L'IA fait 100% du travail", "L'IA remplace le coaching", "L'IA est inutile", "L'IA fait 80% du travail en 20% du temps — vos 20% font 80% de la différence"], "correct_index": 3, "explication": ""}, {"question": "Quelle erreur faut-il éviter avec l'IA ?", "options": ["Copier-coller sans relire — l'audience sent l'inauthenticité", "Utiliser des prompts précis", "Donner du contexte", "Demander des variantes"], "correct_index": 0, "explication": ""}, {"question": "L'IA peut inventer des chiffres et des faits. Il faut donc :", "options": ["Vérifier toujours les informations factuelles", "Tout publier tel quel", "Ne jamais utiliser l'IA", "Ignorer les chiffres"], "correct_index": 0, "explication": ""}, {"question": "Quel logiciel gratuit est recommandé pour le montage vidéo ?", "options": ["iMovie", "VN Video Editor", "Adobe Premiere", "DaVinci Resolve"], "correct_index": 1, "explication": ""}, {"question": "Les sous-titres sont « NON NÉGOCIABLES » car :", "options": ["Instagram les exige", "85% des gens scrollent sans le son", "Ils améliorent le SEO", "Ils sont jolis"], "correct_index": 1, "explication": ""}, {"question": "Le workflow complet de création vidéo est :", "options": ["Filmer → Publier", "IA → Générer → Poster", "Écrire → Filmer → Poster", "Tourner → VN (montage) → Caption/CapCut (sous-titres) → Poster"], "correct_index": 3, "explication": ""}, {"question": "Quelle résolution d'export est recommandée ?", "options": ["720 × 1280", "4K", "1920 × 1080 (16:9)", "1080 × 1920 (9:16)"], "correct_index": 3, "explication": ""}, {"question": "Combien de FPS pour l'export Instagram ?", "options": ["24 FPS", "120 FPS", "60 FPS", "30 FPS"], "correct_index": 3, "explication": ""}, {"question": "La stratégie mois 0-3 est :", "options": ["Déléguer et automatiser", "Lancer des publicités massives", "Valider — définir le client idéal, optimiser le profil, premiers clients", "Créer un site web"], "correct_index": 2, "explication": ""}, {"question": "L'objectif mois 0-3 est :", "options": ["3-5 premiers clients", "10K abonnés", "100 leads", "1000 DMs"], "correct_index": 0, "explication": ""}, {"question": "La stratégie mois 3-6 est :", "options": ["Consolider", "Lancer un 2ème canal", "Traction — contenu gratuit, séquence DM, premier boost, stories à la une", "Recruter une équipe"], "correct_index": 2, "explication": ""}, {"question": "La stratégie mois 6-12 est :", "options": ["Croissance — augmenter les budgets boost, témoignages, optimiser les DMs", "Validation", "Arrêter Instagram", "Se diversifier sur 5 plateformes"], "correct_index": 0, "explication": ""}, {"question": "À 12 mois+, l'objectif est :", "options": ["Recommencer de zéro", "Consolidation — 2ème offre, déléguer, explorer un 2ème canal", "Fermer le business", "Se concentrer uniquement sur les likes"], "correct_index": 1, "explication": ""}, {"question": "Erreur fatale n°1 de la stratégie long terme :", "options": ["Publier trop", "Ne pas utiliser l'IA", "Être partout avant de maîtriser un canal", "Ne pas avoir de site web"], "correct_index": 2, "explication": ""}, {"question": "Erreur fatale « Changer de stratégie tous les 2 mois » — pourquoi ?", "options": ["C'est bon de tester", "Il faut changer chaque semaine", "Une stratégie a besoin de 3-6 mois pour montrer des résultats", "La stratégie n'a pas d'importance"], "correct_index": 2, "explication": ""}, {"question": "La règle d'or n°1 est :", "options": ["Valeur d'abord — donnez avant de demander", "Vendre à tout prix", "Acheter des followers", "Copier les concurrents"], "correct_index": 0, "explication": ""}, {"question": "La règle d'or « Régularité > Perfection » signifie :", "options": ["Un réel moyen 3x/semaine bat un réel parfait 1x/mois", "Publier du contenu de mauvaise qualité", "Ne jamais s'améliorer", "La qualité n'a aucune importance"], "correct_index": 0, "explication": ""}, {"question": "La règle « Pense système » signifie :", "options": ["Automatiser tout", "Déléguer à une agence", "Utiliser des bots", "Réel → profil → DM → vente — c'est un parcours, pas des actions isolées"], "correct_index": 3, "explication": ""}, {"question": "Leila est passée de 0 à combien de CA mensuel en 6 mois ?", "options": ["1 000€", "5 000€", "3 000€", "10 000€"], "correct_index": 1, "explication": ""}, {"question": "Combien Leila a-t-elle investi au total ?", "options": ["0€", "1 000€", "500€", "50€ de boost"], "correct_index": 3, "explication": ""}, {"question": "Le CA total de Leila sur 6 mois était de :", "options": ["5 000€", "~12 000€", "8 000€", "20 000€"], "correct_index": 1, "explication": ""}, {"question": "Quel outil Leila a-t-elle utilisé pour créer son contenu gratuit ?", "options": ["Claude (IA)", "Canva", "ChatGPT", "Photoshop"], "correct_index": 0, "explication": ""}, {"question": "Le taux d'enregistrement est décrit comme :", "options": ["Le signal le plus puissant pour l'algorithme", "Une vanity metric", "Sans importance", "Uniquement pour les carrousels"], "correct_index": 0, "explication": ""}, {"question": "Combien de DMs Leila a-t-elle reçus sur la période ?", "options": ["100", "250", "1000", "420"], "correct_index": 3, "explication": ""}, {"question": "La patience est décrite comme :", "options": ["Optionnelle", "Inutile si on a un bon contenu", "La compétence n°1 — les résultats durables se construisent en 6-12 mois", "Uniquement pour les débutants"], "correct_index": 2, "explication": ""}, {"question": "La règle « Le contenu est le feu » signifie :", "options": ["Il faut beaucoup de contenu", "Le contenu doit être polémique", "La stratégie décide où allumer la flamme — sans contenu, pas de visibilité", "Il faut brûler les étapes"], "correct_index": 2, "explication": ""}], "chapitre_id": "6f94fbf8-9ac2-4d0e-b7ab-a73823cd819b"}$quiz$::jsonb);
SELECT public.import_quiz_from_json($quiz${"titre": "Quiz Marketing Digital — Validation Finale", "description": "300 questions de synthèse. Valide ce quiz pour finaliser la formation.", "max_errors": 3, "status": "published", "questions": [{"question": "Quelle est la définition du marketing digital ?", "options": ["Vendre en ligne uniquement", "Faire de la publicité sur les réseaux sociaux", "Toucher les bonnes personnes, au bon moment, avec le bon message via les canaux numériques", "Créer un site web pour son entreprise"], "correct_index": 2, "explication": ""}, {"question": "Quel avantage le marketing digital a-t-il sur le marketing traditionnel ?", "options": ["Il est toujours gratuit", "Il est mesurable et traçable", "Il ne nécessite aucune compétence", "Il garantit des résultats en 24h"], "correct_index": 1, "explication": ""}, {"question": "Combien peut-on investir au minimum pour démarrer avec du contenu organique ?", "options": ["50€/mois", "0€", "100€/mois", "500€/mois"], "correct_index": 1, "explication": ""}, {"question": "Quels sont les 4 piliers de l'acquisition Instagram ?", "options": ["Pub + Site + Email + Blog", "Bio + Photo + Lien + Certification", "Contenu + Hashtags + Followers + Likes", "Profil + Réels + Stories + Routines de croissance"], "correct_index": 3, "explication": ""}, {"question": "Quelle est la métrique n°1 à suivre selon la formation ?", "options": ["Le nombre de likes", "Le nombre de vues", "Les DMs reçus", "Le nombre d'abonnés"], "correct_index": 2, "explication": ""}, {"question": "Que sont les « vanity metrics » ?", "options": ["Les métriques flatteuses mais qui ne paient pas les factures", "Les métriques qui génèrent du CA", "Les métriques de conversion", "Les métriques de l'algorithme"], "correct_index": 0, "explication": ""}, {"question": "500 abonnés qualifiés valent plus que combien d'abonnés fantômes ?", "options": ["50 000", "10 000", "5 000", "100 000"], "correct_index": 0, "explication": ""}, {"question": "Quel est le bon tunnel de métriques à mesurer ?", "options": ["Likes → Vues → Abonnés → Partages", "DMs reçus → Appels réservés → Clients signés → CA généré", "Impressions → Portée → Engagement → Followers", "Vues → Commentaires → Likes → Partages"], "correct_index": 1, "explication": ""}, {"question": "Dans le parcours client, que se passe-t-il à l'étape « Intrigué » ?", "options": ["Le prospect achète", "Un Réel capte son attention et il visite le profil", "Il répond à un CTA", "Il recommande à un ami"], "correct_index": 1, "explication": ""}, {"question": "Quel est l'ordre correct du parcours Étranger → Client ?", "options": ["Étranger → Client → Prospect → Connecté", "Étranger → Prospect → Intrigué → Client", "Étranger → Intrigué → Connecté → Prospect → Client", "Étranger → Connecté → Client → Prospect"], "correct_index": 2, "explication": ""}, {"question": "À l'étape « Connecté », quel format crée le lien émotionnel ?", "options": ["Les Réels", "Les Stories", "Les publicités", "Les carrousels"], "correct_index": 1, "explication": ""}, {"question": "Quel canal est recommandé comme canal unique au départ ?", "options": ["TikTok", "YouTube", "LinkedIn", "Instagram"], "correct_index": 3, "explication": ""}, {"question": "Que signifie « Scalabilité » en marketing digital ?", "options": ["Réduire les coûts", "Publier plus souvent", "Augmenter le prix de ses services", "Un même contenu peut toucher 1 ou 10 millions de personnes"], "correct_index": 3, "explication": ""}, {"question": "Que signifie « Bidirectionnalité » ?", "options": ["Publier sur deux plateformes", "Faire deux types de contenus", "Dialogue en temps réel avec votre audience", "Avoir deux comptes Instagram"], "correct_index": 2, "explication": ""}, {"question": "Dans le scénario d'Amina, combien de temps lui a-t-il fallu pour atteindre 3 500€/mois ?", "options": ["2 mois", "6 mois", "4 mois", "12 mois"], "correct_index": 2, "explication": ""}, {"question": "Quel budget publicitaire Amina a-t-elle utilisé ?", "options": ["50€/mois", "100€/mois", "500€ au total", "0€ — 100% organique"], "correct_index": 3, "explication": ""}, {"question": "Combien de réels par semaine Amina publiait-elle ?", "options": ["3", "1", "5", "7"], "correct_index": 0, "explication": ""}, {"question": "Combien de stories par jour dans la stratégie d'Amina ?", "options": ["1", "5", "3", "10"], "correct_index": 1, "explication": ""}, {"question": "Quel outil Amina utilisait-elle pour la prise de RDV ?", "options": ["WhatsApp", "Email", "Calendly", "Messenger"], "correct_index": 2, "explication": ""}, {"question": "En combien de temps Amina répondait-elle aux DMs ?", "options": ["15 minutes", "1 heure", "24 heures", "Le lendemain"], "correct_index": 0, "explication": ""}, {"question": "Quel est le rôle des Réels dans les 4 piliers ?", "options": ["Conversion", "Fidélisation", "Moteur de découverte", "Service client"], "correct_index": 2, "explication": ""}, {"question": "Quel est le rôle des Stories dans les 4 piliers ?", "options": ["Découverte", "Publicité", "SEO", "Levier de conversion"], "correct_index": 3, "explication": ""}, {"question": "Que mesurent les « leads capturés » ?", "options": ["Les DMs reçus via vos CTAs", "Le nombre total de vues", "Le nombre de likes", "Les partages de contenu"], "correct_index": 0, "explication": ""}, {"question": "Pourquoi 100K vues sans DM = 0€ de CA ?", "options": ["Parce que l'algorithme est cassé", "Parce que les abonnés ne voient pas le contenu", "Parce qu'Instagram supprime les vues", "Parce que les vues ne se convertissent pas automatiquement en clients"], "correct_index": 3, "explication": ""}, {"question": "Quel est le seul chiffre qui « paie les factures » ?", "options": ["Les clients signés", "Les abonnés", "Les vues", "Les likes"], "correct_index": 0, "explication": ""}, {"question": "Quelle est la règle n°1 de la formation ?", "options": ["Publier 10 réels par jour", "Construire votre écosystème autour d'Instagram", "Acheter des abonnés", "Copier vos concurrents"], "correct_index": 1, "explication": ""}, {"question": "Qu'est-ce que le « setting en DM » ?", "options": ["Configurer son profil Instagram", "Bloquer les spammeurs", "Envoyer des messages automatiques", "Engager une conversation personnalisée en DM avec chaque viewer"], "correct_index": 3, "explication": ""}, {"question": "Que signifie TOFU dans le contexte de la stratégie Amina ?", "options": ["Top Of The Funnel — contenu large", "Type Of Focused User", "Total Organic Funnel Up", "Target Of Future Users"], "correct_index": 0, "explication": ""}, {"question": "Quel jour Amina publiait-elle son contenu BOFU ?", "options": ["Vendredi", "Mercredi", "Lundi", "Dimanche"], "correct_index": 0, "explication": ""}, {"question": "Au mois 1, combien de clientes Amina avait-elle ?", "options": ["8", "3", "0", "18"], "correct_index": 2, "explication": ""}, {"question": "Qu'est-ce que la loi du moindre effort ?", "options": ["Les gens veulent toujours le produit le moins cher", "Le cerveau cherche les moyens les plus simples et économes en énergie", "Les prospects sont paresseux", "Le marketing doit être minimaliste"], "correct_index": 1, "explication": ""}, {"question": "Quel pourcentage de l'énergie du corps le cerveau consomme-t-il ?", "options": ["5%", "10%", "50%", "20%"], "correct_index": 3, "explication": ""}, {"question": "Que signifie WIIFM ?", "options": ["What Is It For Me", "Why Is It For Marketing", "What's In It For Me", "When Is It For Me"], "correct_index": 2, "explication": ""}, {"question": "Quelle est la première question qu'un prospect se pose face à un contenu ?", "options": ["C'est combien ?", "En quoi est-ce utile pour MOI ?", "Qui est cette personne ?", "Est-ce que c'est vrai ?"], "correct_index": 1, "explication": ""}, {"question": "Qu'est-ce que le biais de FOMO ?", "options": ["La peur de se tromper", "La peur de payer trop cher", "La peur de manquer une opportunité", "La peur d'être jugé"], "correct_index": 2, "explication": ""}, {"question": "Combien de fois plus douloureux est-il de perdre que de gagner ?", "options": ["1,5x", "3x", "2x", "5x"], "correct_index": 2, "explication": ""}, {"question": "Qu'est-ce que la preuve sociale ?", "options": ["Montrer ses diplômes", "Publier des photos professionnelles", "On suit le comportement des autres — témoignages et avis rassurent", "Avoir un compte vérifié"], "correct_index": 2, "explication": ""}, {"question": "Qu'est-ce que l'effet de halo ?", "options": ["Une bonne première impression colore tout le reste", "Un filtre Instagram", "Un type de publicité", "Un algorithme Instagram"], "correct_index": 0, "explication": ""}, {"question": "Qu'est-ce que le biais d'ancrage ?", "options": ["Comparer avec les concurrents", "S'accrocher à une idée", "Fixer un prix bas", "Le premier chiffre vu sert de référence pour les suivants"], "correct_index": 3, "explication": ""}, {"question": "Un petit oui mène à un grand oui. Quel biais est-ce ?", "options": ["FOMO", "Réciprocité", "Engagement", "Autorité"], "correct_index": 2, "explication": ""}, {"question": "Que signifie le biais de réciprocité ?", "options": ["Être réciproque dans les DMs", "Rendre la pareille quand on reçoit de la valeur", "Suivre ceux qui nous suivent", "Partager le contenu des autres"], "correct_index": 1, "explication": ""}, {"question": "Quelle est la règle éthique fondamentale concernant les biais ?", "options": ["Utiliser tous les biais en même temps", "Toujours délivrer la valeur promise — jamais de fausse urgence", "Ne jamais utiliser de biais cognitifs", "Cacher l'utilisation des biais"], "correct_index": 1, "explication": ""}, {"question": "Comment appliquer l'urgence sur Instagram ?", "options": ["Publier à heures fixes", "Publier tous les jours", "Utiliser des couleurs vives", "Stories avec compte à rebours, offres limitées, places restreintes"], "correct_index": 3, "explication": ""}, {"question": "Qu'est-ce qui vaut 100 arguments selon la formation ?", "options": ["Un résultat client", "Un bon hook", "Un prix bas", "Un beau visuel"], "correct_index": 0, "explication": ""}, {"question": "Comment créer de la rareté de manière éthique ?", "options": ["Ne publier qu'une fois par mois", "Dire « dernières places » même si c'est faux", "Fermer son compte régulièrement", "Limiter réellement l'accès et délivrer la valeur promise"], "correct_index": 3, "explication": ""}, {"question": "Pourquoi nos ancêtres économisaient-ils leur énergie ?", "options": ["Pour survivre en cas de pénurie", "Pour courir plus vite", "Pour réfléchir mieux", "Pour dormir plus longtemps"], "correct_index": 0, "explication": ""}, {"question": "Les raccourcis mentaux du cerveau s'appellent :", "options": ["Des biais cognitifs", "Des instincts", "Des réflexes", "Des habitudes"], "correct_index": 0, "explication": ""}, {"question": "Comment appliquer la preuve sociale sur Instagram ?", "options": ["Acheter des faux avis", "Mettre beaucoup d'émojis", "Témoignages en Stories, résultats clients en Réels, chiffres en bio", "Avoir un compte vérifié uniquement"], "correct_index": 2, "explication": ""}, {"question": "Omar a doublé ses DMs en combien de temps grâce aux biais ?", "options": ["2 semaines", "1 semaine", "1 mois", "3 mois"], "correct_index": 0, "explication": ""}, {"question": "Quel biais Omar a-t-il utilisé avec le countdown story ?", "options": ["FOMO / Urgence", "Ancrage", "Preuve sociale", "Réciprocité"], "correct_index": 0, "explication": ""}, {"question": "Combien de biais Omar combinait-il par contenu ?", "options": ["1", "Tous", "5-7", "2-3"], "correct_index": 3, "explication": ""}, {"question": "L'analogie de la lionne illustre quel concept ?", "options": ["La force", "La loi du moindre effort — cibler le plus accessible", "La patience", "Le leadership"], "correct_index": 1, "explication": ""}, {"question": "Qu'est-ce que l'aversion à la perte ?", "options": ["Avoir peur de perdre des abonnés", "Perdre fait 2x plus mal que gagner — montrez ce qu'ils perdent", "Ne pas aimer les soldes", "Avoir peur de dépenser"], "correct_index": 1, "explication": ""}, {"question": "Comment appliquer l'ancrage dans une story ?", "options": ["Mettre le prix le plus bas possible", "Ne jamais parler de prix", "Afficher le prix fort avant la promo (ex : 2 000€ barré → 497€)", "Comparer avec un concurrent"], "correct_index": 2, "explication": ""}, {"question": "Quel type de contenu crée de la réciprocité ?", "options": ["Contenu gratuit de valeur — l'audience voudra rendre la pareille", "Contenu payant uniquement", "Contenu humoristique", "Contenu polémique"], "correct_index": 0, "explication": ""}, {"question": "Le biais d'autorité repose sur :", "options": ["Le nombre d'abonnés", "Le nombre de publications", "Le prix élevé", "La confiance envers les experts — résultats et certifications"], "correct_index": 3, "explication": ""}, {"question": "Que signifie « Show don't tell » dans le contexte de la preuve sociale ?", "options": ["Montrer des résultats concrets plutôt que faire des promesses", "Faire des vidéos plutôt que des posts écrits", "Utiliser des visuels plutôt que du texte", "Montrer son visage en vidéo"], "correct_index": 0, "explication": ""}, {"question": "Pour maximiser l'impact, que faut-il faire avec les biais ?", "options": ["N'en utiliser qu'un seul", "Les utiliser uniquement en publicité payante", "Les cacher au prospect", "Les combiner de manière éthique"], "correct_index": 3, "explication": ""}, {"question": "Le highlight « Résultats » d'Omar exploite quel biais ?", "options": ["FOMO", "Preuve sociale", "Ancrage", "Engagement"], "correct_index": 1, "explication": ""}, {"question": "Quel résultat le sondage story d'Omar a-t-il généré ?", "options": ["Des likes", "Des partages", "Un micro-oui → engagement → DM", "Des désabonnements"], "correct_index": 2, "explication": ""}, {"question": "Quelles sont les 5 questions fondatrices d'une stratégie de contenu ?", "options": ["Qui, Quoi, Où, Quand, Comment", "Pourquoi, Pour qui, Quoi, Où, Co